'use client';

export { Tabs, TabsList, TabsTrigger, TabsContent } from './tabs';
export { DynamicTabs } from './dynamic-tabs';
export type { DynamicTabsItem, DynamicTabsProps } from './dynamic-tabs';

'use client';

import * as React from 'react';
import * as TabsPrimitive from '@radix-ui/react-tabs';

import { cn } from '@/lib/utils';
import './index.css';

const Tabs = TabsPrimitive.Root;

const TabsList = React.forwardRef<
  React.ComponentRef<typeof TabsPrimitive.List>,
  React.ComponentPropsWithoutRef<typeof TabsPrimitive.List>
>(({ className, ...props }, ref) => (
  <TabsPrimitive.List
    ref={ref}
    className={cn(
      'jb-tabs-list inline-flex h-8 items-center rounded-[4px] p-1',
      className,
    )}
    {...props}
  />
));
TabsList.displayName = TabsPrimitive.List.displayName;

const TabsTrigger = React.forwardRef<
  React.ComponentRef<typeof TabsPrimitive.Trigger>,
  React.ComponentPropsWithoutRef<typeof TabsPrimitive.Trigger>
>(({ className, ...props }, ref) => (
  <TabsPrimitive.Trigger
    ref={ref}
    className={cn(
      'jb-tabs-trigger inline-flex items-center justify-center whitespace-nowrap rounded-[3px] px-2.5 py-1 text-xs font-medium outline-none transition-[background-color,color,box-shadow] duration-100 ease-in-out disabled:pointer-events-none disabled:opacity-50',
      className,
    )}
    {...props}
  />
));
TabsTrigger.displayName = TabsPrimitive.Trigger.displayName;

const TabsContent = React.forwardRef<
  React.ComponentRef<typeof TabsPrimitive.Content>,
  React.ComponentPropsWithoutRef<typeof TabsPrimitive.Content>
>(({ className, ...props }, ref) => (
  <TabsPrimitive.Content
    ref={ref}
    className={cn(
      'jb-tabs-content mt-2 rounded-[4px] border p-3 text-xs font-normal outline-none',
      className,
    )}
    {...props}
  />
));
TabsContent.displayName = TabsPrimitive.Content.displayName;

export { Tabs, TabsList, TabsTrigger, TabsContent };

'use client';

import * as React from 'react';

import { cn } from '@/lib/utils';
import { Tabs, TabsContent, TabsList, TabsTrigger } from './tabs';

export interface DynamicTabsItem {
  value: string;
  label: React.ReactNode;
  content: React.ReactNode;
  disabled?: boolean;
  triggerClassName?: string;
  contentClassName?: string;
}

export interface DynamicTabsProps
  extends Omit<
    React.ComponentPropsWithoutRef<typeof Tabs>,
    'children' | 'defaultValue' | 'value' | 'onValueChange'
  > {
  items: DynamicTabsItem[];
  value?: string;
  defaultValue?: string;
  onValueChange?: (value: string) => void;
  listClassName?: string;
  triggerClassName?: string;
  contentClassName?: string;
  emptyContent?: React.ReactNode;
}

function DynamicTabs({
  items,
  className,
  listClassName,
  triggerClassName,
  contentClassName,
  value,
  defaultValue,
  onValueChange,
  emptyContent = 'No tabs available.',
  ...props
}: DynamicTabsProps) {
  const firstEnabledValue = React.useMemo(
    () => items.find((item) => !item.disabled)?.value,
    [items],
  );

  if (items.length === 0) {
    return (
      <div
        data-slot="dynamic-tabs-empty"
        className={cn('text-muted-foreground text-sm', className)}
      >
        {emptyContent}
      </div>
    );
  }

  return (
    <Tabs
      className={className}
      value={value}
      defaultValue={defaultValue ?? firstEnabledValue}
      onValueChange={onValueChange}
      {...props}
    >
      <TabsList className={listClassName}>
        {items.map((item) => (
          <TabsTrigger
            key={item.value}
            value={item.value}
            disabled={item.disabled}
            className={cn(triggerClassName, item.triggerClassName)}
          >
            {item.label}
          </TabsTrigger>
        ))}
      </TabsList>

      {items.map((item) => (
        <TabsContent
          key={item.value}
          value={item.value}
          className={cn(contentClassName, item.contentClassName)}
        >
          {item.content}
        </TabsContent>
      ))}
    </Tabs>
  );
}

export { DynamicTabs };

.jb-tabs-list {
  background: var(--jb-tabs-list-bg);
}

.jb-tabs-trigger {
  color: var(--jb-tabs-trigger-text);
}

.jb-tabs-trigger:hover:not(:disabled) {
  background: var(--jb-tabs-trigger-bg-hover);
  color: var(--jb-tabs-trigger-text-hover);
}

.jb-tabs-trigger:focus-visible {
  box-shadow: 0 0 0 2px var(--jb-tabs-trigger-ring);
}

.jb-tabs-trigger[data-state='active'] {
  background: var(--jb-tabs-trigger-bg-active);
  color: var(--jb-tabs-trigger-text-active);
  box-shadow: var(--jb-tabs-trigger-shadow);
}

.jb-tabs-content {
  border-color: var(--jb-tabs-content-border);
  background: var(--jb-tabs-content-bg);
  color: var(--jb-tabs-content-text);
}

.jb-tabs-content:focus-visible {
  box-shadow: 0 0 0 2px var(--jb-tabs-trigger-ring);
}
